import{_ as o,o as a,c as r,a0 as l}from"./chunks/framework.CyG8Xzeu.js";const e="/VC-Lab/assets/%E4%BA%A7%E5%93%81%E5%B1%9E%E6%80%A7.BVK9yDmf.png",i="/VC-Lab/assets/%E7%81%B5%E6%84%9F%E5%8E%9F%E5%9E%8B%E7%A4%BA%E4%BE%8B%E5%9B%BE.D6E0i4Ep.png",b=JSON.parse('{"title":"第二章：产品概念与意象转化","description":"","frontmatter":{},"headers":[],"relativePath":"chapter2/index.md","filePath":"chapter2/index.md"}'),d={name:"chapter2/index.md"};function n(s,t,h,u,q,p){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="第二章-产品概念与意象转化" tabindex="-1">第二章：产品概念与意象转化 <a class="header-anchor" href="#第二章-产品概念与意象转化" aria-label="Permalink to &quot;第二章：产品概念与意象转化&quot;">​</a></h1><blockquote><p>基于已收敛的问题定义（POV + HMW），完成产品概念的具象化定义，并通过意象图、关键词提取与AI生成工具，将抽象的设计语言转化为可视化的产品方向。</p></blockquote><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>经过第一章的认知唤醒与问题洞察，我们已经锁定了一个清晰的核心痛点（选项确认表），并完成了问题收敛（POV + HMW）。然而，这些问题定义仍然是文本层面的。本章的目标是将抽象的&quot;问题-用户-需求&quot;转化为具体的产品概念，并进一步将无形的&quot;产品气质&quot;转化为可视化的设计意象。</p><p>本章包含两个核心环节：</p><ol><li><p><strong>产品定义</strong>：将问题收敛成果转化为一份结构化的产品定义表，明确产品的定位、场景、功能、属性与语义。</p></li><li><p><strong>意象转化</strong>：通过意象图收集、关键词提取与AI概念生成，将抽象语义（如&quot;直觉&quot;&quot;克制&quot;）转化为具象的产品形态、材质与风格。</p></li></ol><p>完成本章后，你将拥有一个明确的产品定义和多个可视化概念方向，为后续的原型设计奠定基础。</p><hr><h2 id="_2-1-产品定义" tabindex="-1">2.1 产品定义 <a class="header-anchor" href="#_2-1-产品定义" aria-label="Permalink to &quot;2.1 产品定义&quot;">​</a></h2><p>产品定义是将问题收敛阶段得到的POV和HMW，转化为一个具体、可描述、可评估的产品概念。它回答了&quot;我们要设计什么&quot;的问题。</p><p>产品定义通常包含以下几个核心要素：</p><ul><li><strong>产品定位</strong>：一句话说清楚&quot;这是什么产品，为谁解决什么问题&quot;</li><li><strong>使用场景</strong>：该产品在什么时间、地点、情境下被使用</li><li><strong>核心功能</strong>：为了实现设计目的，产品必须具备的1-3个关键功能</li><li><strong>产品属性</strong>：从功能、可用性、审美、符号四个维度描述产品特征</li><li><strong>语义定义</strong>：用3-5个形容词概括产品的气质，为后续视觉设计锚定方向</li></ul><p>产品定义是连接&quot;问题空间&quot;与&quot;方案空间&quot;的桥梁。定义越清晰，后续的概念生成与原型设计就越有依据。</p><hr><h3 id="_2-1-1-使用场景" tabindex="-1">2.1.1 使用场景 <a class="header-anchor" href="#_2-1-1-使用场景" aria-label="Permalink to &quot;2.1.1 使用场景&quot;">​</a></h3><p>使用场景分析是从&quot;用户为中心&quot;出发，描绘产品在实际生活中被使用的典型情境。本阶段需要跳出个人经验，通过观察、访谈或移情思考，探索更广泛用户的使用情境。场景特征可以从环境类型、用户行为模式、核心需求等维度进行归纳，形成对产品适用范围的清晰认知。明确场景特征有助于验证功能必要性，并发现不同场景下的设计侧重点。</p><p>我们针对Vibe Coding键盘的使用场景进行了分类：</p><table tabindex="0"><thead><tr><th>场景类型</th><th>特征</th></tr></thead><tbody><tr><td>创客工作室</td><td>多设备协同、高强度创作、强个性化桌面</td></tr><tr><td>移动办公场所</td><td>空间有限、高频收纳、临时搭建工作环境</td></tr><tr><td>社交交流场所</td><td>团队讨论、内容展示、AI协同创作</td></tr><tr><td>固定办公工位</td><td>长时间陪伴、高频使用、桌面生态融合</td></tr></tbody></table><hr><h2 id="📝-学习者任务六-用户使用场景探索" tabindex="-1">📝 学习者任务六：用户使用场景探索 <a class="header-anchor" href="#📝-学习者任务六-用户使用场景探索" aria-label="Permalink to &quot;📝 学习者任务六：用户使用场景探索&quot;">​</a></h2><p><strong>任务</strong>：为你的产品定义2-3个典型使用场景及其特征，跳出自身，至少构想不同用户（例如不同职业、不同年龄段或不同使用习惯）在什么情况下会使用你的产品。</p><p><strong>产出</strong>：一段文字描述，清晰列出2-3个场景及其核心特征。</p><hr><h3 id="_2-1-2-产品属性" tabindex="-1">2.1.2 产品属性 <a class="header-anchor" href="#_2-1-2-产品属性" aria-label="Permalink to &quot;2.1.2 产品属性&quot;">​</a></h3><p>本产品所针对的产品属性：</p><p><img src="'+e+'" alt="产品属性"></p><p><strong>💭 思考问题</strong></p><p>&quot;为什么有人愿意花很高的价格买机械键盘？它满足了哪些非物理属性的需求？&quot;</p><hr><h2 id="📝-学习者任务七-产品属性定义" tabindex="-1">📝 学习者任务七：产品属性定义 <a class="header-anchor" href="#📝-学习者任务七-产品属性定义" aria-label="Permalink to &quot;📝 学习者任务七：产品属性定义&quot;">​</a></h2><p><strong>任务</strong>：基于产品定义，为你的设计方向完成四维属性定义。</p><p><strong>属性关键词头脑风暴</strong>：</p><p>针对每个维度，进行梳理：</p><ul><li><strong>功能</strong>：[关键词]</li><li><strong>可用性</strong>：[关键词]</li><li><strong>审美</strong>：[关键词]</li><li><strong>符号</strong>：[关键词]</li></ul><hr><h3 id="_2-1-3-语义定义" tabindex="-1">2.1.3 语义定义 <a class="header-anchor" href="#_2-1-3-语义定义" aria-label="Permalink to &quot;2.1.3 语义定义&quot;">​</a></h3><p>语义定义是将产品属性转化为可沟通、可感知的设计语言。它回答了&quot;用户会用哪三个词向朋友描述我的产品&quot;。语义定义通常包含以下层次：</p><ol><li><p><strong>核心语义</strong>：用一个最精准的词概括产品的灵魂（如&quot;随心&quot;&quot;伴侣&quot;&quot;利器&quot;）。</p></li><li><p><strong>支撑语义</strong>：用3个左右的词从不同角度支撑核心语义（如&quot;直觉、克制、可靠&quot;）。</p></li><li><p><strong>设计词典（可选）</strong>：将每个语义词转化为具体的设计参数或判断标准，例如&quot;克制&quot; → 语音键不设独立背光，或长按时间需 &gt;0.5 秒。</p></li></ol><p>语义定义是连接&quot;产品属性&quot;与&quot;意象转化&quot;的桥梁。清晰的语义能够指导后续的造型、材质、色彩等设计决策，确保设计语言的一致性。</p><p><strong>引导提问</strong>：</p><blockquote><p>&quot;如果用三个形容词向朋友描述你的产品，你会选哪三个？这三个词就是你的核心语义。&quot;</p></blockquote><hr><h2 id="📝-学习者任务八-从属性到语义" tabindex="-1">📝 学习者任务八：从属性到语义 <a class="header-anchor" href="#📝-学习者任务八-从属性到语义" aria-label="Permalink to &quot;📝 学习者任务八：从属性到语义&quot;">​</a></h2><p><strong>任务</strong>：基于产品属性定义，完成从&quot;属性&quot;到&quot;语义&quot;的转化。</p><p><strong>核心语义提炼</strong></p><p>从产品属性优先级中提炼1个核心语义词和3个支撑语义词。</p><p><strong>模板</strong>：</p><blockquote><p>&quot;这款Vibe Coding键盘的【核心语义】是：______。它通过【支撑语义1】、【支撑语义2】、【支撑语义3】三个维度来体现。&quot;</p></blockquote><p><strong>示范</strong>：</p><blockquote><p>&quot;这款Vibe Coding键盘的核心语义是：创作伴侣。它通过克制（不喧宾夺主）、敏捷（操作一步直达）和温润（触感与视觉亲和）三个维度来体现。&quot;</p></blockquote><p><strong>设计词典构建</strong></p><p>将每个语义词转化为具体的设计参数或判断标准。</p><hr><h2 id="📝-学习者任务九-产品定义" tabindex="-1">📝 学习者任务九：产品定义 <a class="header-anchor" href="#📝-学习者任务九-产品定义" aria-label="Permalink to &quot;📝 学习者任务九：产品定义&quot;">​</a></h2><p><strong>任务</strong>：为你的设计课题完成产品定义，基于POV和HMW及上述使用场景、产品属性与语义定义填写一份完整的产品定义表。注意：产品定位必须具体，避免&quot;一款优秀的产品&quot;等空泛表述。</p><p><strong>产出</strong>：以表格或思维导图的形式产出以下内容。</p><table tabindex="0"><thead><tr><th>要素</th><th>内容</th></tr></thead><tbody><tr><td>产品定位</td><td>（一句话说清楚：为谁？解决什么问题？）</td></tr><tr><td>使用场景</td><td>（列出2-3个典型场景）</td></tr><tr><td>核心功能</td><td>（列出1-3个最必要的功能）</td></tr><tr><td>产品属性</td><td>功能：（关键词）；可用性：（关键词）；审美：（关键词）；符号：（关键词）</td></tr><tr><td>语义定义</td><td>核心语义：（一个词）；支撑语义：（三个词）</td></tr></tbody></table><hr><h2 id="🔧-工具卡3-产品设计蓝图绘制指南" tabindex="-1">🔧 工具卡3：产品设计蓝图绘制指南 <a class="header-anchor" href="#🔧-工具卡3-产品设计蓝图绘制指南" aria-label="Permalink to &quot;🔧 工具卡3：产品设计蓝图绘制指南&quot;">​</a></h2><p><em>此指南帮助您从多个维度具象化你的产品概念。</em></p><table tabindex="0"><thead><tr><th>维度</th><th>内容</th><th>示例</th></tr></thead><tbody><tr><td><strong>活跃舞台</strong></td><td>产品在用户生活中的角色</td><td>Vibe Coding键盘是创作者的&quot;智能助手&quot;</td></tr><tr><td><strong>核心功能</strong></td><td>产品的核心价值点</td><td>一键语音输入、AI快捷键、触觉反馈</td></tr><tr><td><strong>气质感受</strong></td><td>产品传递的情感体验</td><td>克制、敏捷、温润</td></tr><tr><td><strong>用户旅程</strong></td><td>用户与产品互动的完整流程</td><td>打开→连接→使用→收纳</td></tr><tr><td><strong>关键触点</strong></td><td>用户与产品交互的关键时刻</td><td>首次唤醒、日常使用、故障处理</td></tr></tbody></table><hr><h2 id="🔧-工具卡4-语义定义与转化" tabindex="-1">🔧 工具卡4：语义定义与转化 <a class="header-anchor" href="#🔧-工具卡4-语义定义与转化" aria-label="Permalink to &quot;🔧 工具卡4：语义定义与转化&quot;">​</a></h2><p><em>此工具帮助您将抽象的气质转化为可沟通、可执行的设计语言。</em></p><h3 id="语义定义的三个层次" tabindex="-1">语义定义的三个层次 <a class="header-anchor" href="#语义定义的三个层次" aria-label="Permalink to &quot;语义定义的三个层次&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层次</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><strong>核心语义</strong></td><td>产品的灵魂，最精准的一个词</td><td>创作伴侣</td></tr><tr><td><strong>支撑语义</strong></td><td>从不同角度支撑核心语义的3个词</td><td>克制、敏捷、温润</td></tr><tr><td><strong>设计词典</strong></td><td>将语义转化为具体设计参数</td><td>克制 → 无独立背光</td></tr></tbody></table><h3 id="语义-属性关联矩阵-示例" tabindex="-1">语义-属性关联矩阵（示例） <a class="header-anchor" href="#语义-属性关联矩阵-示例" aria-label="Permalink to &quot;语义-属性关联矩阵（示例）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>语义</th><th>功能属性</th><th>可用性属性</th><th>审美属性</th><th>符号属性</th></tr></thead><tbody><tr><td>克制</td><td>功能聚焦</td><td>操作简化</td><td>简约造型</td><td>低调配色</td></tr><tr><td>敏捷</td><td>响应快速</td><td>交互流畅</td><td>轻盈形态</td><td>动态反馈</td></tr><tr><td>温润</td><td>触感舒适</td><td>反馈温和</td><td>柔和材质</td><td>亲和视觉</td></tr></tbody></table><hr><h2 id="🔄-多元视角验证-一" tabindex="-1">🔄 多元视角验证（一） <a class="header-anchor" href="#🔄-多元视角验证-一" aria-label="Permalink to &quot;🔄 多元视角验证（一）&quot;">​</a></h2><p>完成&quot;产品设计蓝图&quot;后，邀请课程群中至少3位背景不同的伙伴（也可小队内互相帮助），向他们展示蓝图并收集反馈。</p><p>单一视角容易产生盲点，多元视角能帮助我们发现隐藏的问题，激发新的灵感，让设计基础更加稳固。请记录他们的主要观点，并思考如何整合这些不同视角，优化设计方向。</p><hr><h2 id="_2-2-意象转化" tabindex="-1">2.2 意象转化 <a class="header-anchor" href="#_2-2-意象转化" aria-label="Permalink to &quot;2.2 意象转化&quot;">​</a></h2><p>通过&quot;意象提取-语言转译-概念生成&quot;的流程，将抽象的产品气质与视觉感受，借助AI图像工具逐渐转化为具有真实产品属性的设计方向。</p><hr><h3 id="_2-2-1-意象选取" tabindex="-1">2.2.1 意象选取 <a class="header-anchor" href="#_2-2-1-意象选取" aria-label="Permalink to &quot;2.2.1 意象选取&quot;">​</a></h3><p><strong>灵感来源</strong>：Pinterest、Dribbble、花瓣网。</p><p>选取相似产品的意象图如下，共性意象关键词：圆润、极简、科技感、精致、模块化、未来感。</p><hr><h2 id="📝-学习者任务十-意象图与关键词提取" tabindex="-1">📝 学习者任务十：意象图与关键词提取 <a class="header-anchor" href="#📝-学习者任务十-意象图与关键词提取" aria-label="Permalink to &quot;📝 学习者任务十：意象图与关键词提取&quot;">​</a></h2><h3 id="意象图收集" tabindex="-1">意象图收集 <a class="header-anchor" href="#意象图收集" aria-label="Permalink to &quot;意象图收集&quot;">​</a></h3><ul><li>在Pinterest/Dribbble/花瓣网搜索与你的设计方向相关的产品意象图</li><li>收集15-20张能代表你心中&quot;理想产品气质&quot;的图片</li><li>范围可以超出键盘品类（建筑、家具、汽车、电子产品均可）</li></ul><h3 id="关键词提取与聚类" tabindex="-1">关键词提取与聚类 <a class="header-anchor" href="#关键词提取与聚类" aria-label="Permalink to &quot;关键词提取与聚类&quot;">​</a></h3><ul><li>为每张图标注1-3个感受关键词</li><li>统计所有关键词出现频次</li><li>筛选出Top 5核心关键词作为设计方向锚点</li></ul><hr><h3 id="_2-2-2-语言转译" tabindex="-1">2.2.2 语言转译 <a class="header-anchor" href="#_2-2-2-语言转译" aria-label="Permalink to &quot;2.2.2 语言转译&quot;">​</a></h3><p>本课程采用：</p><ul><li>Chat GPT image 2</li><li>Nano banana PRO</li></ul><p>进行AI产品概念生成。</p><p>通过意象参考图输入模型，结合提示词确定产品：</p><ul><li>材质倾向</li><li>风格方向</li><li>个性化关键词</li></ul><hr><h3 id="_2-2-3-概念生成" tabindex="-1">2.2.3 概念生成 <a class="header-anchor" href="#_2-2-3-概念生成" aria-label="Permalink to &quot;2.2.3 概念生成&quot;">​</a></h3><h2 id="📝-学习者任务十一-ai概念生成" tabindex="-1">📝 学习者任务十一：AI概念生成 <a class="header-anchor" href="#📝-学习者任务十一-ai概念生成" aria-label="Permalink to &quot;📝 学习者任务十一：AI概念生成&quot;">​</a></h2><p><strong>任务</strong>：基于意象的关键词和属性定义，使用任一生图工具生成至少3个不同方向的Vibe Coding键盘概念图。</p><p><strong>输出要求</strong>：</p><p>每个概念包含：</p><ol><li><strong>概念名称</strong>（如&quot;Flow磁吸键盘&quot;、&quot;Orbit语音模块&quot;）</li><li><strong>核心关键词</strong>（3-5个）</li><li><strong>完整提示词</strong>（中英文均可，需记录）</li><li><strong>概念图</strong>（1-2张）</li></ol><p><strong>方向建议</strong>（可选择一个进行探索）：</p><ul><li><strong>方向A</strong>：极致轻薄/移动优先（偏向便携场景）</li><li><strong>方向B</strong>：模块化/可重组（偏向个性化桌面）</li><li><strong>方向C</strong>：情感化/陪伴感（偏向心理体验）</li><li><strong>方向D</strong>：专业化/功能导向（偏向效率场景）</li></ul><hr><h2 id="📝-灵感实验室-从关键词到视觉原型" tabindex="-1">📝 灵感实验室：从关键词到视觉原型 <a class="header-anchor" href="#📝-灵感实验室-从关键词到视觉原型" aria-label="Permalink to &quot;📝 灵感实验室：从关键词到视觉原型&quot;">​</a></h2><h3 id="第一步-构建灵感共鸣板" tabindex="-1">第一步：构建灵感共鸣板 <a class="header-anchor" href="#第一步-构建灵感共鸣板" aria-label="Permalink to &quot;第一步：构建灵感共鸣板&quot;">​</a></h3><ol><li><p>在Pinterest、花瓣网等平台，广泛搜索与您的&quot;设计语言&quot;（形容词）相关的图片（建筑、家具、艺术品、科技产品等）。收集15-20张能引发&quot;就是这种感觉！&quot;共鸣的图片。</p></li><li><p>为每张图标注1-3个感受关键词（如&quot;流动的线条&quot;、&quot;温暖的木质&quot;）。</p></li><li><p>统计所有关键词，找出出现频率最高的3-5个词，作为 <strong>&quot;视觉密码&quot;</strong>。</p></li></ol><p><img src="'+i+'" alt="灵感原型示例"></p><p><strong>友情链接</strong>：</p><ul><li><a href="https://huaban.com/" target="_blank" rel="noreferrer">https://huaban.com/</a></li><li><a href="https://www.zcool.com.cn/" target="_blank" rel="noreferrer">https://www.zcool.com.cn/</a></li></ul><h3 id="第二步-感官想象与内在化" tabindex="-1">第二步：感官想象与内在化 <a class="header-anchor" href="#第二步-感官想象与内在化" aria-label="Permalink to &quot;第二步：感官想象与内在化&quot;">​</a></h3><p>闭上眼睛，想象理想中的产品就在面前。尝试回答：</p><ul><li><strong>触觉</strong>：它的表面是什么温度？什么纹理？（是冰凉金属的理性，还是温暖木质的亲和？）</li><li><strong>听觉</strong>：操作它时，会发出什么声音？（是清脆的&quot;咔嗒&quot;声，还是静默的流畅感？）</li><li><strong>嗅觉</strong>：它会有气味吗？（是新电子产品的淡淡气味，还是天然材料的清香？）</li><li><strong>情感</strong>：触摸和使用它时，你内心最希望感受到哪种情绪？（是专注的平静，还是创造的兴奋？）</li></ul><p>将你的感受记录下来，这些将丰富你的&quot;视觉密码&quot;。</p><h3 id="第三步-召唤视觉原型" tabindex="-1">第三步：召唤视觉原型 <a class="header-anchor" href="#第三步-召唤视觉原型" aria-label="Permalink to &quot;第三步：召唤视觉原型&quot;">​</a></h3><ol><li><p><strong>组合提示词</strong>：将&quot;产品类型&quot;、&quot;核心/支撑语义词&quot;、&quot;视觉密码&quot;及&quot;感官想象&quot;中的关键词，组合成给AI生图工具的&quot;描述咒语&quot;。</p><p>例如：<code>&quot;一个具有[温润]和[克制]气质的[智能键盘模块]，设计灵感来源于[流动的线条]，触感[细腻微凉]，整体风格[极简]、[未来感]。&quot;</code></p><p><strong>友情链接</strong>：</p><ul><li><a href="https://chat.openai.com" target="_blank" rel="noreferrer">https://chat.openai.com</a></li><li><a href="https://google.com/gemini" target="_blank" rel="noreferrer">https://google.com/gemini</a></li></ul></li><li><p><strong>生成与迭代</strong>：使用提示词生成图像，并调整描述进行多轮生成，获得3-5张在不同方向上令您惊喜的&quot;视觉原型&quot;图。</p></li><li><p><strong>命名与记录</strong>：为每个概念方向命名（如&quot;磐石&quot;、&quot;流萤&quot;），并记录最终使用的提示词。</p></li></ol><hr><h2 id="🔄-概念快速验证-简易原型测试" tabindex="-1">🔄 概念快速验证：简易原型测试 <a class="header-anchor" href="#🔄-概念快速验证-简易原型测试" aria-label="Permalink to &quot;🔄 概念快速验证：简易原型测试&quot;">​</a></h2><p>选择最满意的两个&quot;视觉原型&quot;概念，用纸板、黏土或任何手边材料，在10分钟内制作一个能表达其<strong>核心交互或形态特征</strong>的简易实体模型。向一位朋友（不一定是设计背景）展示，并只用1分钟解释：&quot;这是一个为解决[Who的核心问题]而设计的[产品]，它的特点是[XXX]。&quot;观察他们的第一反应，并询问一个简单问题：&quot;你觉得它可能怎么用？&quot;记录反馈。这个快速测试能验证概念是否被直观理解，是想法落地前的重要试炼。</p><hr><h2 id="📝-学习者任务汇总" tabindex="-1">📝 学习者任务汇总 <a class="header-anchor" href="#📝-学习者任务汇总" aria-label="Permalink to &quot;📝 学习者任务汇总&quot;">​</a></h2><p>完成第二章后，你将产出：</p><ol><li>一份&quot;灵感共鸣板&quot;（图片集+关键词统计）</li><li>一份&quot;感官想象&quot;记录</li><li>一组（3-5张）&quot;视觉原型&quot;图及说明</li><li>&quot;简易原型测试&quot;的记录与反思</li></ol><hr><h2 id="🔄-阶段回顾与心态调整-二" tabindex="-1">🔄 阶段回顾与心态调整（二） <a class="header-anchor" href="#🔄-阶段回顾与心态调整-二" aria-label="Permalink to &quot;🔄 阶段回顾与心态调整（二）&quot;">​</a></h2><p>完成第二章所有任务后，进行阶段性回顾。</p><p><strong>1. 回顾与检视</strong>：回顾从&quot;战略地图&quot;到&quot;视觉原型&quot;的整个旅程。你的产品定义是否始终回应了最初的POV？在&quot;长远考量&quot;和&quot;价值锚点&quot;的思考中，你对&quot;好设计&quot;的理解是否有新的维度？简易原型测试带来了什么新启发？</p><p><strong>2. 心态与展望</strong>：为在整个探索过程中获得的每一个灵感、每一次突破、甚至每一个挫折而珍视。真正的创造源于深刻的洞察、持续的努力以及对用户和世界的一份责任感。带着这些收获，准备进入下一阶段的深化设计。</p><hr><div style="text-align:center;margin:3rem 0;"><a href="/VC-Lab/chapter3/" class="learn-more-btn"><span class="circle" aria-hidden="true"><span class="icon arrow"></span></span><span class="button-text">继续学习第三章</span></a></div><div class="theme-toggle-container"><label class="bb8-toggle" title="Toggle theme"><input type="checkbox" class="bb8-toggle__checkbox"><div class="bb8-toggle__container"><div class="bb8-toggle__star"></div><div class="bb8-toggle__star"></div><div class="bb8-toggle__star"></div><div class="bb8-toggle__star"></div><div class="bb8-toggle__star"></div><div class="bb8-toggle__star"></div><div class="bb8-toggle__star"></div><div class="bb8"><div class="bb8__head-container"><div class="bb8__head"><div class="bb8__antenna"></div><div class="bb8__antenna"></div></div></div><div class="bb8__body"></div></div><div class="bb8__shadow"></div><div class="bb8-toggle__scenery"><div class="bb8-toggle__cloud"></div><div class="bb8-toggle__cloud"></div><div class="bb8-toggle__cloud"></div></div></div></label></div><div class="back-to-top" id="backToTop"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 19V5M5 12l7-7 7 7" stroke-linecap="round" stroke-linejoin="round"></path></svg></div>',131)])])}const c=o(d,[["render",n]]);export{b as __pageData,c as default};
